from flask import Flask, request, jsonify
import torch
from torchvision import models, transforms
from PIL import Image
import io
import os

app = Flask(__name__)

# Load a pre-trained model
model = models.resnet50(pretrained=True)
model.eval()

# Define a simple transformation
transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Load class names
with open('imagenet_classes.txt') as f:
    class_names = [line.strip() for line in f.readlines()]

def secure_predict(image_bytes):
    image = Image.open(io.BytesIO(image_bytes))
    image = transform(image).unsqueeze(0)
    with torch.no_grad():
        outputs = model(image)
    _, predicted = outputs.max(1)
    confidence = torch.nn.functional.softmax(outputs, dim=1)[0] * 100
    return class_names[predicted[0]], confidence[predicted[0]].item()

@app.route('/predict', methods=['POST'])
def predict():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    try:
        image_bytes = file.read()
        class_name, confidence = secure_predict(image_bytes)
        return jsonify({'class': class_name, 'confidence': confidence})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use a proper SSL certificate in production